import React from "react";
import { motion } from "framer-motion";

const pageVariants = {
  initial: { opacity: 0, x: "-100vw" }, // เริ่มจากนอกจอซ้าย
  animate: { opacity: 1, x: 0 }, // เลื่อนเข้ามา
  exit: { opacity: 0, x: "100vw" } // ออกจากจอขวา
};

const Home = () => {
  return (
    <motion.div
      className="home-container"
      initial="initial"
      animate="animate"
      exit="exit"
      variants={pageVariants}
      transition={{ duration: 0.5 }} // ทำให้ลื่นไหล
    >
      <h1>Home Page</h1>
      <p>Welcome to the Capturing Booth!</p>
    </motion.div>
  );
};

export default Home;
